# add-step-1.1.ps1
# Étape 1.1 du Sprint 1 : constantes + types
# Usage : depuis la racine du repo Decibel-Dash, lancer :
#   PowerShell -ExecutionPolicy Bypass -File .\add-step-1.1.ps1

$ErrorActionPreference = "Stop"

Write-Host "Sprint 1 - Étape 1.1 : Constantes + types" -ForegroundColor Cyan
Write-Host "Cible : $PWD" -ForegroundColor Gray
Write-Host ""

$files = @(
    @{ Path = 'src\config\audio.ts'; B64 = '' },
    @{ Path = 'src\config\physics.test.ts'; B64 = '' },
    @{ Path = 'src\config\physics.ts'; B64 = '' },
    @{ Path = 'src\config\spawn.ts'; B64 = '' },
    @{ Path = 'src\config\world.ts'; B64 = '' },
    @{ Path = 'src\types\index.ts'; B64 = '' }
)

$created = 0
foreach ($f in $files) {
    $fullPath = Join-Path $PWD $f.Path
    $dir = Split-Path $fullPath -Parent
    if (-not (Test-Path $dir)) {
        New-Item -ItemType Directory -Path $dir -Force | Out-Null
    }
    $bytes = [Convert]::FromBase64String($f.B64)
    [IO.File]::WriteAllBytes($fullPath, $bytes)
    Write-Host "  + $($f.Path)" -ForegroundColor Green
    $created++
}

Write-Host ""
Write-Host "$created fichiers créés." -ForegroundColor Cyan
Write-Host ""
Write-Host "Vérification :" -ForegroundColor Yellow
Write-Host "  pnpm typecheck" -ForegroundColor White
Write-Host "  pnpm test" -ForegroundColor White
